    return (
        <>
            <div className='home-container'>
                <h1 className='home-title'>Pc Garage</h1>
            </div>
            <ListaOp />
        </>
    );
}
function ListaOp()
{
    const navigate = useNavigate();
    const handleLoginButton = () =>
    {
       navigate('/');
    };
    return (
        <div className='lista-container'>
            <button onClick={handleLoginButton}>
                Log in
            </button>
        </div>
    );
}

export default HomePage;
